import React from "react";
import { useParams } from "react-router-dom";

export default function RoomDetails() {
  const { id } = useParams();

  return (
    <div style={{ padding: 50, color: "white", background: "black" }}>
      <h1>Room Details Page</h1>
      <p>Room ID: {id}</p>
    </div>
  );
}
